## Wzorzec Command Bus — CQRS

```php
// Command (DTO) — intencja z walidacją
final readonly class RegisterUserCommand
{
    public function __construct(
        public string $email,
        public string $password,
        public string $name,
    ) {}
}

// Handler — logika biznesowa
class RegisterUserHandler
{
    public function __construct(
        private UserRepositoryInterface $users,
        private PasswordHasher $hasher,
        private EventDispatcher $events,
    ) {}

    public function handle(RegisterUserCommand $cmd): User
    {
        if ($this->users->findByEmail($cmd->email)) {
            throw new EmailAlreadyTakenException($cmd->email);
        }
        $user = new User(
            email: $cmd->email,
            password: $this->hasher->hash($cmd->password),
        );
        $this->users->save($user);
        $this->events->dispatch(new UserRegisteredEvent($user));
        return $user;
    }
}

// Kontroler jest cienki
class AuthController
{
    public function register(Request $request): Response
    {
        $cmd = new RegisterUserCommand(
            email: $request->get('email'),
            password: $request->get('password'),
            name: $request->get('name'),
        );
        $user = $this->commandBus->dispatch($cmd);
        return new JsonResponse(['id' => $user->getId()], 201);
    }
}
```
